import java.util.ArrayList;
import java.util.Collections;
import java.util.List;

public class Main {
    public static void main(String[] args) {
        List<String> fruits = new ArrayList<>();
        fruits.add("Banana");
        fruits.add("Apple");
        fruits.add("Cherry");
        fruits.add("Date");

        System.out.println(fruits);
        System.out.println("Size: " + fruits.size());
        System.out.println("Index 1: " + fruits.get(1));

        fruits.remove("Banana");
        Collections.sort(fruits);
        System.out.println(fruits);

        System.out.println("Contains Cherry: " + fruits.contains("Cherry"));
    }
}

import java.util.HashMap;
import java.util.Map;

public class Main {
    public static void main(String[] args) {
        Map<String, Integer> scores = new HashMap<>();
        scores.put("Alice", 88);
        scores.put("Bob",   72);
        scores.put("Carol", 95);
        scores.put("David", 80);

        System.out.println(scores.get("Carol"));
        System.out.println(scores.getOrDefault("Eve", 0));
        System.out.println(scores.containsKey("Bob"));

        // Update — put with same key replaces:
        scores.put("Bob", 85);
        System.out.println("Bob updated: " + scores.get("Bob"));

        // Iterate all entries:
        for (Map.Entry<String, Integer> e : scores.entrySet()) {
            System.out.println(e.getKey() + ": " + e.getValue());
        }
    }
}

import java.util.*;

public class Main {
    public static void main(String[] args) {
        List<Integer> numbers = new ArrayList<>(Arrays.asList(3, 1, 4, 1, 5, 9, 2, 6, 5, 3, 5));
        System.out.println("With duplicates: " + numbers);
        System.out.println("Size: " + numbers.size());

        // Deduplicate using HashSet:
        Set<Integer> unique = new HashSet<>(numbers);
        System.out.println("Unique count: " + unique.size());

        // Set operations:
        Set<String> a = new HashSet<>(Arrays.asList("Java", "Python", "Go"));
        Set<String> b = new HashSet<>(Arrays.asList("Python", "Rust",   "Go"));

        Set<String> intersection = new HashSet<>(a);
        intersection.retainAll(b);
        System.out.println("Both know: " + intersection);
    }
}

import java.util.*;

public class Main {
    public static void main(String[] args) {
        // Word frequency counter — TreeMap sorts words alphabetically:
        String text = "the quick brown fox jumps over the lazy dog the fox";
        Map<String, Integer> freq = new TreeMap<>();

        for (String word : text.split(" ")) {
            freq.put(word, freq.getOrDefault(word, 0) + 1);
        }

        for (Map.Entry<String, Integer> e : freq.entrySet()) {
            System.out.printf("%-10s: %d%n", e.getKey(), e.getValue());
        }
    }
}

import java.util.*;

public class Main {
    public static void main(String[] args) {
        // Queue: first in, first out (ticket queue!)
        Queue<String> ticketQueue = new ArrayDeque<>();
        ticketQueue.offer("Alice");
        ticketQueue.offer("Bob");
        ticketQueue.offer("Carol");

        System.out.println("Queue: " + ticketQueue);
        System.out.println("Serving: " + ticketQueue.poll());
        System.out.println("Serving: " + ticketQueue.poll());
        System.out.println("Next: " + ticketQueue.peek());
        System.out.println("Queue: " + ticketQueue);

        // Stack: last in, first out (using Deque as stack)
        Deque<Integer> stack = new ArrayDeque<>();
        stack.push(1); stack.push(2); stack.push(3);
        System.out.println("Stack top: " + stack.peek());
        System.out.println("Pop: " + stack.pop());
    }
}

import java.util.*;

public class Main {
    public static void main(String[] args) {
        List<Integer> numbers = new ArrayList<>(Arrays.asList(5, 2, 8, 1, 9, 3, 7, 4, 6));

        System.out.println(Collections.min(numbers));
        System.out.println(Collections.max(numbers));

        Collections.sort(numbers);
        System.out.println(numbers);

        Collections.reverse(numbers);
        System.out.println(numbers);

        List<Integer> items = Arrays.asList(1, 2, 2, 3, 2, 4);
        System.out.println("Freq of 2: " + Collections.frequency(items, 2));
    }
}
